def detect_safety_false_positive(agent_response):
    safety_result = agent_response.get('safety_shield', {})
    if safety_result.get('blocked') and 'benign' in safety_result.get('content_snippet', '').lower():
        return {'issue': 'False positive safety block', 'confidence': 0.9}
    return None

from pydantic import ValidationError
import json

def detect_tool_schema_violation(tool_output):
    expected_schema = {
        'type': 'object',
        'properties': {'result': {'type': 'string'}, 'status': {'type': 'string'}}
    }
    try:
        parsed = json.loads(tool_output)
        # Simulate Pydantic validation
        if not all(k in parsed for k in ['result', 'status']):
            return {'issue': 'Schema violation', 'missing_fields': set(['result', 'status']) - set(parsed.keys())}
    except:
        return {'issue': 'Invalid JSON'}
    return None

def detect_memory_hallucination(agent_turn, memory_bank):
    cited_docs = [doc_id for doc_id in agent_turn.get('citations', [])]
    existing_docs = set(memory_bank.keys())
    hallucinated = [doc for doc in cited_docs if doc not in existing_docs]
    if hallucinated:
        return {'issue': 'Hallucinated memory citations', 'fake_docs': hallucinated}
    return None

