from vex_sdk import verify
from llama_stack_client import LlamaStackAgent

agent = LlamaStackAgent()

def agent_turn_with_vex(prompt):
    raw_response = agent.run(prompt)

    verified = verify(
        response=raw_response,
        checks=[
            'llama_stack_safety_false_positive',
            'tool_schema_conformance',
            'memory_citation_validity'
        ],
        framework='llama-stack',
        remediation=True
    )

    if verified['status'] == 'PASS':
        return verified['response']
    else:
        return {'error': verified['issues'], 'fixed': verified['remediated']}
